{"command":"cat > /tmp/rebuild.js << 'EOF'
const fs = require('fs');
const path = require('path');

const HISTORY_DIR = 'history';
const COUNTS_FILE = path.join(HISTORY_DIR, 'session_counts.json');

// Find all session files
const files = fs.readdirSync(HISTORY_DIR)
  .filter(f => f.startsWith('session_') && f.endsWith('.json') && !f.includes('sessions_manifest'))
  .map(f => path.join(HISTORY_DIR, f));

console.log(`Found ${files.length} session files`);

// Initialize counts
const counts = {
  totalSessions: 0,
  totalDiscoveries: 0,
  totalObstacles: 0,
  totalActions: 0,
  totalTestsPassed: 0,
  practicesUsed: {},
  filesTouched: {},
  actionCounts: {},
  lastUpdated: new Date().toISOString()
};

// Process each file
let errors = 0;
let processed = 0;

files.forEach(file => {
  try {
    const data = JSON.parse(fs.readFileSync(file, 'utf-8'));

    // Skip files that don't look like session records
    if (!data.journey || !data.meta) {
      console.log(`Skipping non-session file: ${path.basename(file)}`);
      return;
    }

    counts.totalSessions++;
    counts.totalDiscoveries += (data.journey.discoveries || []).length;
    counts.totalObstacles += (data.journey.obstacles || []).length;
    counts.totalActions += (data.journey.actions || []).length;
    counts.totalTestsPassed += data.meta.testsPassed || 0;

    // Update practices
    (data.meta.practicesExercised || []).forEach(practice => {
      counts.practicesUsed[practice] = (counts.practicesUsed[practice] || 0) + 1;
    });

    // Update files touched
    (data.meta.filesModified || []).forEach(file => {
      counts.filesTouched[file] = (counts.filesTouched[file] || 0) + 1;
    });

    // Update action counts
    (data.journey.actions || []).forEach(action => {
      if (action.type) {
        counts.actionCounts[action.type] = (counts.actionCounts[action.type] || 0) + 1;
      }
    });

    processed++;
  } catch (e) {
    errors++;
    console.log(`Error processing ${path.basename(file)}: ${e.message}`);
  }
});

// Save counts
fs.writeFileSync(COUNTS_FILE, JSON.stringify(counts, null, 2));

console.log(`\nProcessed: ${processed}`);
console.log(`Errors: ${errors}`);
console.log(`\nTotal sessions: ${counts.totalSessions}`);
console.log(`Total discoveries: ${counts.totalDiscoveries}`);
console.log(`Total obstacles: ${counts.totalObstacles}`);
console.log(`Total actions: ${counts.totalActions}`);
console.log(`Total tests passed: ${counts.totalTestsPassed}`);
console.log(`\nPractices used: ${Object.keys(counts.practicesUsed).length} types`);
console.log(`Action types: ${Object.keys(counts.actionCounts).join(', ') || 'none'}`);
EOF
